// scripts/build-metadata.mjs
//
// Captures the version + repo-wide coverage snapshot rendered as the
// header badge strip on the homepage. Output → src/routes/metadata.json,
// committed to the repo so a fresh checkout shows real numbers without
// re-running anything. Re-generated by `pnpm coverage` (chained after
// the per-bit coverage + git-status snapshots) and `pnpm meta` for
// ad-hoc refresh.
//
// Two data sources:
//   1. Versions — `pnpm ls --json --depth=0` resolves the installed
//      versions of all top-level deps (semver ranges in package.json
//      hide minor/patch, the lockfile carries the exact pinned version
//      pnpm actually installed; `pnpm ls` is the canonical lookup).
//      Plus `pnpm --version` for the package manager itself.
//   2. Overall coverage — the `total` row of coverage-summary.json that
//      vitest emits via the 'json-summary' reporter. Same source the
//      per-bit aggregator uses, but pulling the pre-summed totals
//      instead of recomputing them.
//
// Output shape:
//   {
//     "versions": {
//       "svelte": "5.55.9",
//       "tailwindcss": "4.3.0",
//       "bits-ui": "2.18.1",
//       "typescript": "6.0.3",
//       "vitest": "4.1.7",
//       "pnpm": "9.15.4"
//     },
//     "overall": { "lines": 100, "statements": 100, "branches": 100, "functions": 100 }
//   }

import { execSync } from 'node:child_process';
import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import { resolve } from 'node:path';

const repoRoot = resolve(import.meta.dirname, '..');
const summaryPath = resolve(repoRoot, 'coverage/coverage-summary.json');
const outputPath = resolve(repoRoot, 'apps/playground/src/routes/metadata.json');

// 1. Versions. `pnpm ls` walks a real install graph so this only works
//    after `pnpm install`. The shape merges dependencies + devDependencies
//    because some packages (tailwindcss, bits-ui, svelte) move between
//    those buckets across releases and we don't want a bucket move to
//    silently drop a badge.
const PICK = ['svelte', 'tailwindcss', 'bits-ui', 'typescript', 'vitest'];
const versions = {};

try {
    const lsRaw = execSync('pnpm ls --json --depth=0', { cwd: repoRoot, encoding: 'utf8' });
    const pkg = JSON.parse(lsRaw)[0];
    const all = { ...pkg.dependencies, ...pkg.devDependencies };
    for (const name of PICK) {
        if (all[name]?.version) versions[name] = all[name].version;
    }
} catch (err) {
    console.warn(`[build-metadata] pnpm ls failed (${err.message}); version badges will be empty.`);
}

// pnpm's own version is independent of the workspace's deps — it's the
// package manager binary the user has installed. Falls back silently to
// no badge if pnpm isn't on PATH (e.g. in a non-pnpm CI runner).
try {
    versions.pnpm = execSync('pnpm --version', { encoding: 'utf8' }).trim();
} catch (err) {
    console.warn(`[build-metadata] pnpm --version failed (${err.message}); skipping pnpm badge.`);
}

// 2. Overall coverage — read the pre-summed `total` row. v8 already
//    aggregates across every instrumented file, so we don't need to
//    recompute from per-file rows. Missing summary → omit the overall
//    block; the homepage gracefully renders without those badges.
let overall = null;
if (existsSync(summaryPath)) {
    try {
        const summary = JSON.parse(readFileSync(summaryPath, 'utf8'));
        const total = summary.total;
        if (total) {
            overall = {
                lines: Math.round(total.lines.pct * 10) / 10,
                statements: Math.round(total.statements.pct * 10) / 10,
                branches: Math.round(total.branches.pct * 10) / 10,
                functions: Math.round(total.functions.pct * 10) / 10,
            };
        }
    } catch (err) {
        console.warn(`[build-metadata] coverage-summary.json unreadable (${err.message}).`);
    }
} else {
    console.warn(`[build-metadata] ${summaryPath} not found — overall coverage badges will be omitted.`);
}

const output = { versions, ...(overall ? { overall } : {}) };
writeFileSync(outputPath, JSON.stringify(output, null, 2) + '\n');

const vCount = Object.keys(versions).length;
const cov = overall
    ? ` + overall coverage L${overall.lines}/S${overall.statements}/B${overall.branches}/F${overall.functions}`
    : '';
console.log(`[build-metadata] Wrote ${vCount} versions${cov} → ${outputPath}`);
